package com.gdxgame;

import com.badlogic.gdx.Gdx;
import com.badlogic.gdx.backends.headless.HeadlessApplication;
import com.badlogic.gdx.backends.headless.HeadlessApplicationConfiguration;

import java.io.IOException;
import java.nio.file.Path;
import java.nio.file.Paths;

/**
 * Entry point for the headless grid walker simulation.
 *
 * Accepts --input=&lt;file&gt; to specify the keystroke replay file.
 * Boots a HeadlessApplication, overwrites the default MockInput with
 * a ScriptedInput, and blocks until the simulation completes.
 */
public class Launcher {

    public static void main(String[] args) {
        Path inputFile = null;

        for (String arg : args) {
            if (arg.startsWith("--input=")) {
                inputFile = Paths.get(arg.substring("--input=".length()));
            }
        }

        if (inputFile == null) {
            System.err.println("Error: missing required argument --input=<file>");
            System.exit(1);
            return;
        }

        ScriptedInput scriptedInput;
        try {
            scriptedInput = new ScriptedInput(inputFile);
        } catch (IOException e) {
            System.err.println("Error: cannot read input file: " + inputFile);
            System.exit(1);
            return;
        } catch (IllegalArgumentException e) {
            System.err.println(e.getMessage());
            System.exit(1);
            return;
        }

        HeadlessApplicationConfiguration config = new HeadlessApplicationConfiguration();
        config.updatesPerSecond = 60;

        WalkerGame game = new WalkerGame(scriptedInput);

        HeadlessApplication app = new HeadlessApplication(game, config);

        // Overwrite the default MockInput with our ScriptedInput so that
        // Gdx.input.setInputProcessor() routes through our subclass.
        Gdx.input = scriptedInput;

        // Block until the application exits (which happens after the script is exhausted).
        // HeadlessApplication runs the listener on its own thread, so we need to wait.
        while (true) {
            try {
                Thread.sleep(100);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                break;
            }
            // Check if the app has finished (Gdx.app.exit() was called).
            // There is no public API to check this, but we can detect it by checking
            // if the listener thread has finished. A simpler approach: check a flag.
            if (scriptedInput.isExhausted()) {
                // Give a small grace period for the final render to print and exit
                try {
                    Thread.sleep(200);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }
                break;
            }
        }
    }
}

